// ============================================================
// FULL API INTEGRATION (Frontend → Backend)
// ============================================================

import axios from "axios";

const BASE_URL = "http://localhost:5000/api";

// ================= AUTH =================

export const loginUser = async (data) => {
  const res = await axios.post(`${BASE_URL}/auth/login`, data);
  localStorage.setItem("token", res.data.token);
  return res.data;
};

export const registerUser = async (data) => {
  const res = await axios.post(`${BASE_URL}/auth/register`, data);
  return res.data;
};

// ================= USER =================

export const getProfile = async () => {
  const token = localStorage.getItem("token");

  const res = await axios.get(`${BASE_URL}/users/profile`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  return res.data;
};

// ================= BOOKS =================

export const getBooks = async () => {
  const res = await axios.get(`${BASE_URL}/books`);
  return res.data;
};

export const addBook = async (data) => {
  const token = localStorage.getItem("token");

  const res = await axios.post(`${BASE_URL}/books`, data, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  return res.data;
};

// ================= ISSUE =================

export const issueBook = async (data) => {
  const token = localStorage.getItem("token");

  const res = await axios.post(`${BASE_URL}/issues`, data, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  return res.data;
};

export const returnBook = async (id) => {
  const token = localStorage.getItem("token");

  const res = await axios.put(`${BASE_URL}/issues/${id}/return`, {}, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  return res.data;
};

// ================= FINES =================

export const getFines = async () => {
  const token = localStorage.getItem("token");

  const res = await axios.get(`${BASE_URL}/fines`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  return res.data;
};

// ================= REQUEST =================

export const requestCard = async (data) => {
  const token = localStorage.getItem("token");

  const res = await axios.post(`${BASE_URL}/libraryCards`, data, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  return res.data;
};
